import{c as a,Q as s,j as i,m as t}from"./chunks/framework.DVkeSyfh.js";const m=JSON.parse('{"title":"Search and Tag Writing","description":"","frontmatter":{},"headers":[],"relativePath":"search-and-tags.md","filePath":"search-and-tags.md","lastUpdated":1779998571000}'),r={name:"search-and-tags.md"};function o(c,e,l,d,n,h){return s(),i("div",null,[...e[0]||(e[0]=[t(`<h1 id="search-and-tag-writing" tabindex="-1">Search and Tag Writing <a class="header-anchor" href="#search-and-tag-writing" aria-label="Permalink to &quot;Search and Tag Writing&quot;">​</a></h1><p>This page covers the search tabs, classifier filtering surface, and the explicit genre-tag write workflow.</p><h2 id="search-modes" tabindex="-1">Search Modes <a class="header-anchor" href="#search-modes" aria-label="Permalink to &quot;Search Modes&quot;">​</a></h2><p>The search panel has separate tabs.</p><p>The library browser also has a <code>syncopated</code> preset filter. It selects tracks whose stored MAEST metadata has <code>maest_syncopated_rhythm = true</code> and can be combined with normal library text search and the add-filtered-tracks workflow.</p><p>The CLASS tab contains classifier controls discovered from promoted <code>models/classifiers/*/model.json</code> metadata. Each promoted classifier can be analyzed from the UI, and its slider filters the library and add-filtered-tracks workflow by <code>track_classifier_scores.score</code>.</p><h3 id="sonara-search" tabindex="-1">SONARA Search <a class="header-anchor" href="#sonara-search" aria-label="Permalink to &quot;SONARA Search&quot;">​</a></h3><p>SONARA is the primary explainable seed-search path. It sends selected seed tracks, optional lookback tracks, limit, minimum similarity, mixer weights, and modifiers to <code>/api/search/sonara</code>.</p><p>Mixer weights:</p><ul><li><code>timbre</code></li><li><code>rhythm</code></li><li><code>dynamics</code></li><li><code>harmonic</code></li><li><code>tempo</code></li></ul><p>Modifiers:</p><ul><li><code>energy</code></li><li><code>valence</code></li><li><code>acousticness</code></li><li><code>brightness</code></li><li><code>rhythm_density</code></li><li><code>dynamic_range</code></li><li><code>loudness</code></li></ul><p>The backend still accepts preset mode names for compatibility:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>balanced, vibe, sound, dj_transition, custom</span></span></code></pre></div><p>The active UI path uses the custom mixer.</p><h3 id="mert-search" tabindex="-1">MERT Search <a class="header-anchor" href="#mert-search" aria-label="Permalink to &quot;MERT Search&quot;">​</a></h3><p>MERT seed search sends seed tracks, lookback tracks, limit, and optional minimum similarity to <code>/api/search</code>. It ranks tracks in the MERT embedding space.</p><h3 id="clap-text-search" tabindex="-1">CLAP Text Search <a class="header-anchor" href="#clap-text-search" aria-label="Permalink to &quot;CLAP Text Search&quot;">​</a></h3><p>CLAP text search sends a text prompt, limit, optional minimum similarity, and device to <code>/api/search/text</code>. It ranks CLAP audio vectors against a CLAP text vector.</p><p>Concrete English prompts usually work best:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Melancholic minimal house with broken drums, warm chords, no vocals</span></span>
<span class="line"><span>Dark hypnotic techno with sparse percussion and deep rolling bass</span></span>
<span class="line"><span>Organic microhouse with soft pads, plucked textures, and spacious mood</span></span></code></pre></div><h3 id="class-classifiers" tabindex="-1">CLASS / Classifiers <a class="header-anchor" href="#class-classifiers" aria-label="Permalink to &quot;CLASS / Classifiers&quot;">​</a></h3><p>The CLASS tab is for classifier-driven workflows rather than similarity search. It lists promoted classifiers discovered from <code>models/classifiers/*/model.json</code>:</p><ul><li><code>Analyze &lt;classifier&gt;</code> starts a cancellable classifier job.</li><li>Each classifier slider filters the library server-side by stored classifier score.</li><li>The metadata dialog shows classifier scores, confidence, label, feature set, and model file below SONARA features.</li></ul><p>Promoted classifiers require a promoted model file and feature-complete tracks. They do not analyze audio directly; run SONARA, MERT, and MAEST first for the tracks you want to score.</p><h2 id="tag-writing" tabindex="-1">Tag Writing <a class="header-anchor" href="#tag-writing" aria-label="Permalink to &quot;Tag Writing&quot;">​</a></h2><p>MAEST genre saving writes one normalized semicolon-separated genre string, for example:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Tech House; Minimal; Techno</span></span></code></pre></div><p>MAEST category prefixes such as <code>Electronic---</code> are stripped before writing.</p><p>Format-specific genre fields:</p><ul><li>MP3, WAV, AIFF ID3 tags: <code>TCON</code></li><li>FLAC and Vorbis-style tags: <code>GENRE</code></li><li>MP4, M4A, ALAC: <code>©gen</code></li></ul><p>WAV genre writing uses Mutagen&#39;s <code>WAVE</code> support, saves the <code>TCON</code> value, and verifies that the saved value can be read afterward. It does not run a custom RIFF repair step. If a WAV write or readback fails, that track is reported as failed while the batch continues.</p>`,32)])])}const u=a(r,[["render",o]]);export{m as __pageData,u as default};
